import{_ as d,o as r,c as a,a7 as o}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"血肉界域（Caro）","description":"","frontmatter":{},"headers":[],"relativePath":"realms/caro.md","filePath":"zh/realms/caro.md","lastUpdated":1775394001000}'),e={name:"realms/caro.md"};function l(s,t,i,n,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="血肉界域-caro" tabindex="-1">血肉界域（Caro） <a class="header-anchor" href="#血肉界域-caro" aria-label="Permalink to &quot;血肉界域（Caro）&quot;">​</a></h1><p><span class="realm-badge realm-caro">血肉 Caro</span></p><h2 id="界域特性" tabindex="-1">界域特性 <a class="header-anchor" href="#界域特性" aria-label="Permalink to &quot;界域特性&quot;">​</a></h2><p>血肉界域以<strong>胚胎系统</strong>为核心机制，通过吞噬胚胎触发强力的爆发效果。v2.4版本界域强度评级为 <strong>S级</strong>，神父+专武后与深海并列。上手难度最高。</p><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><ul><li><strong>胚胎系统</strong> — 血肉界域才能发动后，队伍头上显示胚胎量表。量表通过血肉觉醒体的技能等积蓄（胚融合），达到100%时向手牌中加入1张「胚」卡片</li><li><strong>吞噬效果</strong> — 手中持有「胚」卡时，可与血肉角色的狂气爆发技能配合发动「吞噬」效果，消耗「胚」来触发超强力效果</li><li><strong>至纯血肉</strong> — 纯血肉编成时触发特殊增强效果</li><li><strong>胚胎引擎</strong> — 雷娅吞噬胚胎大量回血，艾继丝生产/管理胚胎。界域精通34+可自然每回合+35胚融合值</li></ul><h2 id="血肉界域唤醒体" tabindex="-1">血肉界域唤醒体 <a class="header-anchor" href="#血肉界域唤醒体" aria-label="Permalink to &quot;血肉界域唤醒体&quot;">​</a></h2><table tabindex="0"><thead><tr><th>唤醒体</th><th>定位</th><th>Tier</th><th>获取方式</th></tr></thead><tbody><tr><td>尤乌哈希 (Uvhash)</td><td>输出</td><td>T0</td><td>常驻/活动唤醒</td></tr><tr><td>雷娅 (Rhea)</td><td>辅助</td><td>T0</td><td>常驻/活动唤醒</td></tr><tr><td>索蕾尔 (Sorel)</td><td>输出</td><td>T0</td><td>限定活动唤醒</td></tr><tr><td>泰旖丝 (Thais)</td><td>辅助</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>爱丽丝 (Alice)</td><td>副输出</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>萨尔瓦多 (Salvador)</td><td>防御</td><td>—</td><td>唤醒</td></tr><tr><td>艾继丝 (Aigis)</td><td>辅助</td><td>—</td><td>唤醒</td></tr><tr><td>菲茵特 (Faint)</td><td>副输出</td><td>T2</td><td>常驻/活动唤醒</td></tr><tr><td>阿格里帕 (Agrippa)</td><td>防御</td><td>T2</td><td>常驻/活动唤醒</td></tr><tr><td>希洛 (Shilo)</td><td>输出</td><td>T3</td><td>常驻/活动唤醒</td></tr><tr><td>血链·希洛 (Helot)</td><td>输出</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>杜勒赛因 (Doresain)</td><td>输出</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>莱 (Leigh)</td><td>合唱</td><td>—</td><td>常驻唤醒</td></tr><tr><td>徐 (Xu)</td><td>合唱</td><td>—</td><td>限定活动唤醒</td></tr></tbody></table><h2 id="构筑建议" tabindex="-1">构筑建议 <a class="header-anchor" href="#构筑建议" aria-label="Permalink to &quot;构筑建议&quot;">​</a></h2><ol><li><strong>尤乌哈希血肉队</strong> — 尤乌哈希+雷娅+艾继丝+菲茵特（标准血肉，觉醒优先：艾继丝&gt;雷娅&gt;尤乌&gt;菲茵特）</li><li><strong>神父队</strong> — 萨尔瓦多+雷娅+艾继丝+24/拉蒙娜（公认Top3最强阵容之一。神父+专武后将血肉推至S级）</li><li><strong>24血肉变体</strong> — 24+希洛/雷娅+艾继丝+萨尔瓦多（24的血肉共鸣：算力消耗=胚融合+力量增益）</li></ol><div class="tip custom-block"><p class="custom-block-title">新手建议</p><p>血肉的上手难度最高，开荒时很难把控血量与胚胎的优势。雷娅+艾继丝是血肉队不可替代的「2」，优先培养。每场战斗结束时保持一个辅助能量满+胚融合70-100%。</p></div>',11)])])}const m=d(e,[["render",l]]);export{p as __pageData,m as default};
